        // Visitor skips all links entirely
        var _testVisitor = new TestVisitor();
        class TestVisitor : IVisitor
        {
            public VisitResult VisitLink(VisitContext ctx, string href, string text, string title)
            {
                return VisitResult.Skip();
            }
        }
        var result = HtmlToMarkdownRs.Convert("<p>Before <a href=\"https://example.com\">link text</a> after</p>", null, _testVisitor);
        Assert.DoesNotContain("link text", result.Content.ToString());
        Assert.DoesNotContain("example.com", result.Content.ToString());
    }

