    [Fact]
    public void Test_VisitorVideoCustom()
    {
        // Visitor replaces video with custom link
        var _testVisitor = new TestVisitor();
        class TestVisitor : IVisitor
        {
            public VisitResult VisitVideo(VisitContext ctx, string src)
            {
                return VisitResult.Custom($"[VIDEO: {src}]");
            }
        }
        var result = HtmlToMarkdownRs.Convert("<p>Watch our tutorial:</p><video src=\"tutorial.mp4\" width=\"320\" height=\"240\" controls></video><p>Great content!</p>", null, _testVisitor);
        Assert.Contains("[video: tutorial.mp4]", result.Content.ToString().ToLower());
        Assert.Contains("watch our tutorial:", result.Content.ToString().ToLower());
        Assert.Contains("great content!", result.Content.ToString().ToLower());
    }

